#include <iostream>
#include <unordered_map>
#include <string>
#include <chrono>

class Session {
public:
    std::string data;
    std::time_t expiryTime;

    Session(std::string data, std::time_t expiry) : data(data), expiryTime(expiry) {}
};

class CachingSystem {
private:
    std::unordered_map<std::string, Session*> cache;
    static const std::time_t SESSION_EXPIRY_TIME = 3600; // 1 hour

public:
    ~CachingSystem() {
        for (auto& pair : cache) {
            delete pair.second;
        }
    }

    void createSession(const std::string& sessionId, const std::string& data) {
        if (!cache.count(sessionId)) {
            std::time_t expiry = std::chrono::system_clock::to_time_t(std::chrono::system_clock::now() + SESSION_EXPIRY_TIME);
            cache[sessionId] = new Session(data, expiry);
        }
    }

    bool accessSession(const std::string& sessionId) {
        if (cache.count(sessionId)) {
            auto now = std::chrono::system_clock::to_time_t(std::chrono::system_clock::now());
            if (cache[sessionId]->expiryTime > now) {
                return true;
            } else {
                delete cache[sessionId];
                cache.erase(sessionId);
            }
        }
        return false;
    }

    void invalidateSession(const std::string& sessionId) {
        if (cache.count(sessionId)) {
            delete cache[sessionId];
            cache.erase(sessionId);
        }
    }
};

